import{c as d,Q as o,j as i,m as e}from"./chunks/framework.D0Y1hua4.js";const b=JSON.parse('{"title":"信心","description":"","frontmatter":{},"headers":[],"relativePath":"notes/培训/Meeting/信心.md","filePath":"notes/培训/Meeting/信心.md"}'),t={name:"notes/培训/Meeting/信心.md"};function p(a,r,g,n,s,l){return o(),i("div",null,[...r[0]||(r[0]=[e('<h1 id="信心" tabindex="-1">信心 <a class="header-anchor" href="#信心" aria-label="Permalink to &quot;信心&quot;">​</a></h1><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:24px;margin:20px 0;color:#333;"><blockquote style="margin:0;padding:8px 12px;border-left:3px solid #667eea;background:rgba(102,126,234,0.05);border-radius:4px;color:#555;">💡 <strong>如果多给你三年时间，你有信心考上 985、211 吗？</strong></blockquote><blockquote style="margin:8px 0 0 0;padding:8px 12px;border-left:3px solid #667eea;background:rgba(102,126,234,0.05);border-radius:4px;color:#555;">💡 <strong>如果让你现在去做小学一年级的试卷，你有信心拿满分吗？</strong></blockquote></div><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:20px;margin:20px 0;color:#333;"><h3>🤔 为什么我们常常感到缺乏信心？</h3><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;margin-top:12px;border-left:4px solid #667eea;"><p>信心，往往在行动尚未开始之前就已显现——它源于一个人的内心状态，正如情绪一样可以被塑造。</p></div><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;margin-top:12px;border-left:4px solid #667eea;"><blockquote style="margin:0;padding:8px 12px;border-left:3px solid #667eea;background:rgba(102,126,234,0.05);border-radius:4px;color:#555;">假如今天你和女朋友分手，感到难过；但若明天遇到更合适的人，你是否会重新开心起来？</blockquote><p>同样，你觉得工作累不累、苦不苦，很大程度上也取决于你的心态。</p></div><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;margin-top:12px;border-left:4px solid #667eea;"><blockquote style="margin:0;padding:8px 12px;border-left:3px solid #667eea;background:rgba(102,126,234,0.05);border-radius:4px;color:#555;">篮球运动员在场上奔跑得汗流浃背，他们会觉得那是负担吗？</blockquote><blockquote style="margin:8px 0 0 0;padding:8px 12px;border-left:3px solid #667eea;background:rgba(102,126,234,0.05);border-radius:4px;color:#555;">回想童年，和小伙伴在田里追逐打闹、扔泥巴的时候，你会感到疲惫吗？</blockquote><p>那么，今天我们从事的这份工作，到底累不累？</p><p>说不累是假的。每天两三万步，身体当然会累。但区别在于，我们的焦点放在&quot;赚钱&quot;上，因此难以像玩耍那样全心投入。</p></div><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;margin-top:12px;border-left:4px solid #667eea;"><p>我刚入行时也曾困惑：为什么没人监督，还要这么拼命奔跑？</p><p>答案很简单：因为我们想要的，不止于此。一旦&quot;打钟&quot;，就能带观察日、带徒弟、建队发展，实现晋升与达标。</p></div></div><div style="background:rgba(239,68,68,0.06);border:1px solid rgba(239,68,68,0.15);border-radius:12px;padding:20px;margin:20px 0;color:#333;"><h3>⚠️ 为什么我们会失去信心？</h3><div style="background:rgba(239,68,68,0.08);padding:12px;border-radius:8px;margin-top:12px;border-left:4px solid #ef4444;"><p>往往是因为长期自我否定，总觉得自己&quot;做不到&quot;&quot;不行&quot;。</p><p>我们必须建立正确的认知：把信心建立在<strong>系统</strong>之上——比如&quot;五八六四平均法&quot;，而不是依赖顾客、组长或领队的反馈。</p></div></div><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:20px;margin:20px 0;color:#333;text-align:center;font-size:1.2em;"><h3>✨ 信心，来自于&quot;可预见的未来&quot;</h3></div><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:20px;margin:20px 0;color:#333;"><p>我们之所以愿意奔跑，是因为我们看得到发展路径：公司的每一位经理、主管，无不是从基层业务起步。这就是系统的力量——没有人天生就会销售，但我们从零起步，一路有人带、有人教、有意向客户时有人帮。</p><p>从&quot;不会&quot;到&quot;会&quot;，需要过程，也需要时间。</p><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;margin-top:12px;text-align:center;border-left:4px solid #667eea;"><blockquote style="margin:0;padding:8px 12px;border-left:3px solid #667eea;background:rgba(102,126,234,0.05);border-radius:4px;color:#555;">🛤️ 从这里到重庆，你可以选择飞机、高铁、动车，甚至骑行或自驾。最终都能抵达，只是时间长短不同。</blockquote></div></div><div style="margin:20px 0;"><h3>⏱️ 影响速度快慢的因素</h3><div style="display:flex;flex-wrap:wrap;gap:12px;margin-top:12px;"><div style="flex:1;min-width:200px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:16px;color:#333;"><p><strong>🏢 公司起跑线</strong></p><p>公司提供的起跑线是相同的：平台与晋升机制。</p></div><div style="flex:1;min-width:200px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:16px;color:#333;"><p><strong>👤 个人起点不同</strong></p><p>每个人的起点不同：认知、经历、原生家庭、所处圈子……二十年养成的习惯，改变需要过程。</p></div><div style="flex:1;min-width:200px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:16px;color:#333;"><p><strong>📊 客观因素</strong></p><p>此外，还有客观因素：比如产品周期、市场波动，甚至公司是否正处于低谷期。</p></div></div></div><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:20px;margin:20px 0;color:#333;text-align:center;font-size:1.1em;"><h3>🔄 只要系统在、方法在、方向在，信心，就可以一直都在。</h3></div><div style="margin:20px 0;"><h3>🧠 好的心态与正确的方法</h3><h4>一、核心心态：成功的基石</h4><div style="display:flex;flex-wrap:wrap;gap:12px;margin-top:12px;"><div style="flex:1;min-width:200px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:16px;color:#333;"><div style="font-size:1.5em;margin-bottom:8px;">🥤</div><strong>人生两杯水的哲学</strong><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;margin-top:8px;border-left:4px solid #667eea;"><ul style="margin:0;padding-left:20px;"><li><strong>人生两杯水</strong>：一杯苦水，一杯甜水，终须喝完。</li><li><strong>核心区别</strong>：是主动面对，还是被动地将其混合，浑浑噩噩地度过？</li></ul></div></div><div style="flex:1;min-width:200px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:16px;color:#333;"><div style="font-size:1.5em;margin-bottom:8px;">💪</div><strong>没有失败，只有放弃与学习</strong><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;margin-top:8px;border-left:4px solid #667eea;"><ul style="margin:0;padding-left:20px;"><li><strong>核心理念</strong>：<strong>只有放弃，没有失败</strong>。因为&quot;我在，我的生意就在&quot;。</li><li><strong>正确看待挫折</strong>：暂时的&quot;没做好&quot;是一次<strong>学习</strong>的机会，学习如何调整自我，并坚信自己能够再次站起来。</li><li><strong>关键能力</strong>：学会从错误和失败中走出来。</li></ul></div></div><div style="flex:1;min-width:200px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:16px;color:#333;"><div style="font-size:1.5em;margin-bottom:8px;">🤝</div><strong>信任系统，排除自我干扰</strong><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;margin-top:8px;border-left:4px solid #667eea;"><ul style="margin:0;padding-left:20px;"><li><strong>根本原则</strong>：多数问题源于将<strong>个人因素</strong>（如情绪、怀疑、临时发挥）加到了系统中，从而干扰了系统的正常运作。</li></ul></div></div></div></div><div style="margin:20px 0;"><h4>二、方法论基石：营销系统</h4><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:16px;margin-top:12px;color:#333;"><p>我们的系统是经过验证的，包含：</p><div style="display:flex;flex-wrap:wrap;gap:12px;margin-top:12px;"><div style="flex:1;min-width:150px;background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;text-align:center;border-left:4px solid #667eea;"><div style="font-size:2em;">5️⃣</div><strong>五步</strong></div><div style="flex:1;min-width:150px;background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;text-align:center;border-left:4px solid #667eea;"><div style="font-size:2em;">8️⃣</div><strong>八点</strong></div><div style="flex:1;min-width:150px;background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;text-align:center;border-left:4px solid #667eea;"><div style="font-size:2em;">📊</div><strong>平均法</strong></div><div style="flex:1;min-width:150px;background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;text-align:center;border-left:4px solid #667eea;"><div style="font-size:2em;">🔥</div><strong>冲动文化</strong></div></div></div></div><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:20px;margin:20px 0;color:#333;"><h3>📐 关于&quot;平均法&quot;的重点认知</h3><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;margin-top:12px;border-left:4px solid #667eea;"><ul style="margin:0;padding-left:20px;"><li><strong>本质是概率学</strong>：成功遵循统计规律。</li><li><strong>关键要求</strong>：不要将自己的主观想法和个别案例的得失，强加于这个概率系统之上。<strong>坚持执行，结果必然发生</strong>。</li></ul></div></div><div style="margin:20px 0;"><h3>📞 三、实战步骤：客户沟通三部曲</h3><div style="display:flex;flex-wrap:wrap;gap:12px;margin-top:12px;"><div style="flex:1;min-width:200px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:16px;color:#333;"><div style="font-size:1.5em;margin-bottom:8px;">1️⃣</div><strong>客户分类与破冰</strong><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;margin-top:8px;border-left:4px solid #667eea;"><p><strong>客户类型（仅有三种）</strong></p></div><div style="display:flex;flex-wrap:wrap;gap:8px;margin-top:8px;"><div style="flex:1;min-width:100px;background:rgba(34,197,94,0.08);padding:12px;border-radius:8px;text-align:center;border:1px solid rgba(34,197,94,0.15);"><div style="font-size:1.5em;">✅</div><strong>要</strong><p>有明确需求的客户</p></div><div style="flex:1;min-width:100px;background:rgba(239,68,68,0.08);padding:12px;border-radius:8px;text-align:center;border:1px solid rgba(239,68,68,0.15);"><div style="font-size:1.5em;">❌</div><strong>不要</strong><p>明确拒绝的客户</p></div><div style="flex:1;min-width:100px;background:rgba(245,158,11,0.08);padding:12px;border-radius:8px;text-align:center;border:1px solid rgba(245,158,11,0.15);"><div style="font-size:1.5em;">⭐</div><strong>可要可不要</strong><p>最重要的潜在客户群，是工作的核心重点</p></div></div><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;margin-top:8px;border-left:4px solid #667eea;"><p><strong>破冰的关键</strong></p><ul style="margin:0;padding-left:20px;"><li><strong>目标</strong>：通过<strong>打招呼</strong>和<strong>专业的自我介绍</strong>来分辨客户类型。</li><li><strong>成败关键</strong>：客户是否愿意听你讲，取决于你<strong>所传递的感觉</strong>。</li></ul></div></div><div style="flex:1;min-width:200px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:16px;color:#333;"><div style="font-size:1.5em;margin-bottom:8px;">2️⃣</div><strong>执行核心流程</strong><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;margin-top:8px;border-left:4px solid #667eea;"><ul style="margin:0;padding-left:20px;"><li><strong>核心目标</strong>：想办法让客户<strong>听完&quot;五步&quot;</strong> 的完整介绍。</li><li><strong>工作重心</strong>：将 <strong>&quot;可要可不要&quot;的客户转化为&quot;要&quot;的客户</strong>。</li></ul></div></div><div style="flex:1;min-width:200px;background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:16px;color:#333;"><div style="font-size:1.5em;margin-bottom:8px;">3️⃣</div><strong>复盘与优化</strong><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;margin-top:8px;border-left:4px solid #667eea;"><ul style="margin:0;padding-left:20px;"><li><strong>检查点</strong>：如果客户听完了&quot;五步&quot;却未成交。</li><li><strong>复盘重点</strong>：必须反思和优化从 <strong>&quot;介绍产品&quot;到&quot;成交&quot;</strong> 这两个步骤的细节。</li></ul></div></div></div></div><div style="background:rgba(102,126,234,0.06);border:1px solid rgba(102,126,234,0.15);border-radius:12px;padding:20px;margin:20px 0;color:#333;text-align:center;"><h3>🏆 总结</h3><div style="background:rgba(102,126,234,0.08);padding:16px;border-radius:8px;margin-top:12px;font-size:1.1em;border-left:4px solid #667eea;"><p><strong>积极心态 → 信任系统 → 专业破冰 → 筛选客户 → 完整讲解 → 重点转化 → 复盘优化</strong></p></div><div style="background:rgba(102,126,234,0.08);padding:12px;border-radius:8px;margin-top:12px;text-align:left;border-left:4px solid #667eea;"><blockquote style="margin:0;padding:8px 12px;border-left:3px solid #667eea;background:rgba(102,126,234,0.05);border-radius:4px;color:#555;">这套方法的精髓在于：以积极的心态为基础，完全信任并执行系统化的流程，通过概率法则和专业的沟通技巧，实现持续的成功。</blockquote></div></div>',13)])])}const u=d(t,[["render",p]]);export{b as __pageData,u as default};
